function RssMonitor() {
  const [url, setUrl] = React.useState('REPLACE_WITH_FEED_URL');
  const [items, setItems] = React.useState([]);
  const [seenIds, setSeenIds] = React.useState(new Set());
  const [status, setStatus] = React.useState('idle');
  const fetchFeed = async () => {
    if (!url) return;
    setStatus('fetching');
    try {
      const r = await titan.api.call('/api/rss/parse', { method: 'POST', body: { url } });
      const list = (r?.items || []).slice(0, 30);
      setItems(prev => {
        const newSeen = new Set(seenIds);
        let hadNew = false;
        for (const it of list) {
          const id = it.id || it.link || it.title;
          if (!newSeen.has(id)) { newSeen.add(id); if (seenIds.size > 0) hadNew = true; }
        }
        setSeenIds(newSeen);
        if (hadNew) { try { new Audio('https://actions.google.com/sounds/v1/alarms/beep_short.ogg').play(); } catch {} }
        return list.map(it => ({ ...it, _id: it.id || it.link || it.title, _fresh: !seenIds.has(it.id || it.link || it.title) }));
      });
      setStatus('ok');
    } catch (e) { setStatus('error: ' + (e?.message||e)); }
  };
  React.useEffect(() => { fetchFeed(); const id = setInterval(fetchFeed, 300000); return () => clearInterval(id); }, [url]);
  return (
    <div style={{padding:12,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{display:'flex',gap:6,marginBottom:10}}>
        <input value={url} onChange={e=>setUrl(e.target.value)} placeholder="RSS URL" style={{flex:1,padding:'6px 10px',border:'1px solid #ccc',borderRadius:6,fontSize:13}}/>
        <button onClick={fetchFeed} style={{padding:'6px 14px',borderRadius:6,border:'none',background:'#007AFF',color:'#fff',cursor:'pointer'}}>↻</button>
      </div>
      <div style={{fontSize:11,color:'#888',marginBottom:6}}>Status: {status} · Auto-refresh every 5 min</div>
      <div style={{flex:1,overflow:'auto'}}>
        {items.length === 0 ? <div style={{textAlign:'center',color:'#888',padding:20}}>No items.</div> :
          items.map((it,i) => (
            <a key={it._id||i} href={it.link} target="_blank" rel="noopener noreferrer"
              style={{display:'block',padding:'8px 10px',borderBottom:'1px solid #f0f0f0',textDecoration:'none',color:'#222',background:it._fresh?'#FFF7E6':'transparent'}}>
              <div style={{fontSize:13,fontWeight:600}}>{it._fresh && <span style={{color:'#FF9500',marginRight:4}}>●</span>}{it.title}</div>
              <div style={{fontSize:11,color:'#888',marginTop:2}}>{it.pubDate ? new Date(it.pubDate).toLocaleString() : ''}</div>
            </a>
          ))
        }
      </div>
    </div>
  );
}
render(<RssMonitor/>);
